"""
تمام استایل‌ها (CSS)، اسکریپت‌های جاوااسکریپت و لوگوی سایت به‌صورت رشته پایتون در همین فایل قرار دارند
تا نیازی به پوشه static جداگانه نباشد.
"""

LOGO_DATA_URI = "data:image/jpeg;base64,"

CSS_TEXT = ":root {\n  --bg: #f6f5ff;\n  --bg-soft: #ffffff;\n  --text: #201a3a;\n  --text-muted: #635e7a;\n  --primary: #7c3aed;\n  --primary-2: #ec4899;\n  --accent: #f59e0b;\n  --success: #16a34a;\n  --card-border: rgba(124, 58, 237, 0.15);\n  --shadow: 0 10px 30px rgba(124, 58, 237, 0.12);\n  --radius: 18px;\n}\n\n[data-theme=\"dark\"] {\n  --bg: #0f0b23;\n  --bg-soft: #1a1436;\n  --text: #f2f0ff;\n  --text-muted: #b3aed1;\n  --primary: #a78bfa;\n  --primary-2: #f472b6;\n  --accent: #fbbf24;\n  --success: #4ade80;\n  --card-border: rgba(167, 139, 250, 0.25);\n  --shadow: 0 10px 30px rgba(0, 0, 0, 0.4);\n}\n\n* { box-sizing: border-box; }\n\nbody {\n  margin: 0;\n  font-family: \"Vazirmatn\", Tahoma, sans-serif;\n  background: var(--bg);\n  color: var(--text);\n  direction: rtl;\n  transition: background 0.3s ease, color 0.3s ease;\n  min-height: 100vh;\n}\n\na { color: inherit; text-decoration: none; }\n\n.container {\n  max-width: 1080px;\n  margin: 0 auto;\n  padding: 0 20px;\n}\n\n/* ---------- Navbar ---------- */\n.navbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 16px 24px;\n  background: var(--bg-soft);\n  box-shadow: var(--shadow);\n  position: sticky;\n  top: 0;\n  z-index: 50;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  font-weight: 800;\n  font-size: 1.4rem;\n  background: linear-gradient(90deg, var(--primary), var(--primary-2));\n  -webkit-background-clip: text;\n  background-clip: text;\n  color: transparent;\n}\n\n.brand .logo-dot {\n  width: 14px;\n  height: 14px;\n  border-radius: 50%;\n  background: linear-gradient(135deg, var(--accent), var(--primary-2));\n  box-shadow: 0 0 12px var(--accent);\n}\n\n.nav-links {\n  display: flex;\n  gap: 6px;\n  flex-wrap: wrap;\n}\n\n.nav-links a {\n  padding: 8px 14px;\n  border-radius: 999px;\n  font-weight: 600;\n  font-size: 0.92rem;\n  color: var(--text-muted);\n}\n\n.nav-links a:hover, .nav-links a.active {\n  background: linear-gradient(90deg, var(--primary), var(--primary-2));\n  color: #fff;\n}\n\n.theme-toggle {\n  border: none;\n  cursor: pointer;\n  border-radius: 999px;\n  padding: 8px 16px;\n  font-weight: 700;\n  background: var(--bg);\n  color: var(--text);\n  border: 1px solid var(--card-border);\n}\n\n/* ---------- Hero ---------- */\n.hero {\n  text-align: center;\n  padding: 60px 20px 40px;\n}\n\n.hero h1 {\n  font-size: 2.2rem;\n  margin-bottom: 10px;\n  background: linear-gradient(90deg, var(--primary), var(--primary-2), var(--accent));\n  -webkit-background-clip: text;\n  background-clip: text;\n  color: transparent;\n}\n\n.hero p {\n  color: var(--text-muted);\n  font-size: 1.05rem;\n  max-width: 640px;\n  margin: 0 auto;\n}\n\n/* ---------- Cards / Forms ---------- */\n.card {\n  background: var(--bg-soft);\n  border: 1px solid var(--card-border);\n  border-radius: var(--radius);\n  box-shadow: var(--shadow);\n  padding: 28px;\n  margin: 20px auto;\n}\n\n.form-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 16px;\n}\n\n@media (max-width: 640px) {\n  .form-grid { grid-template-columns: 1fr; }\n}\n\n.field { display: flex; flex-direction: column; gap: 6px; }\n\nlabel { font-weight: 600; font-size: 0.9rem; color: var(--text-muted); }\n\ninput, select, textarea {\n  padding: 12px 14px;\n  border-radius: 12px;\n  border: 1px solid var(--card-border);\n  background: var(--bg);\n  color: var(--text);\n  font-family: inherit;\n  font-size: 0.95rem;\n}\n\ninput:focus, select:focus, textarea:focus {\n  outline: none;\n  border-color: var(--primary);\n}\n\n.btn {\n  display: inline-block;\n  cursor: pointer;\n  border: none;\n  padding: 13px 26px;\n  border-radius: 999px;\n  font-weight: 700;\n  font-size: 0.98rem;\n  background: linear-gradient(90deg, var(--primary), var(--primary-2));\n  color: #fff;\n  transition: transform 0.15s ease, box-shadow 0.15s ease;\n}\n\n.btn:hover { transform: translateY(-2px); box-shadow: 0 8px 18px rgba(124,58,237,0.35); }\n\n.btn.secondary {\n  background: transparent;\n  border: 2px solid var(--primary);\n  color: var(--primary);\n}\n\n.btn.gold {\n  background: linear-gradient(90deg, var(--accent), var(--primary-2));\n}\n\n.btn.block { width: 100%; text-align: center; }\n\n/* ---------- Day cards for study plan ---------- */\n.day-card {\n  border: 1px solid var(--card-border);\n  border-radius: 14px;\n  padding: 16px 18px;\n  margin-bottom: 12px;\n  background: var(--bg);\n}\n\n.day-card .day-title {\n  font-weight: 800;\n  color: var(--primary);\n  margin-bottom: 8px;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n\n.day-tag {\n  font-size: 0.75rem;\n  padding: 3px 10px;\n  border-radius: 999px;\n  background: linear-gradient(90deg, var(--accent), var(--primary-2));\n  color: #fff;\n}\n\n.item-row {\n  display: flex;\n  justify-content: space-between;\n  padding: 6px 0;\n  border-bottom: 1px dashed var(--card-border);\n  font-size: 0.9rem;\n}\n.item-row:last-child { border-bottom: none; }\n.item-row .subject-name { font-weight: 700; }\n.item-row .minutes { color: var(--text-muted); font-size: 0.8rem; }\n\n/* ---------- Pricing ---------- */\n.pricing-grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n  gap: 18px;\n}\n\n.price-card {\n  background: var(--bg-soft);\n  border: 1px solid var(--card-border);\n  border-radius: var(--radius);\n  padding: 24px 20px;\n  text-align: center;\n  box-shadow: var(--shadow);\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n}\n\n.price-card .price {\n  font-size: 1.5rem;\n  font-weight: 800;\n  background: linear-gradient(90deg, var(--primary), var(--primary-2));\n  -webkit-background-clip: text;\n  background-clip: text;\n  color: transparent;\n}\n\n/* ---------- Leaderboard ---------- */\n.leader-row {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 14px 18px;\n  border-radius: 14px;\n  margin-bottom: 10px;\n  background: var(--bg-soft);\n  border: 1px solid var(--card-border);\n}\n\n.leader-row.top-1 { border: 2px solid var(--accent); }\n.leader-row.top-2 { border: 2px solid #c0c0c0; }\n.leader-row.top-3 { border: 2px solid #cd7f32; }\n\n.rank-badge {\n  width: 34px; height: 34px;\n  border-radius: 50%;\n  display: flex; align-items: center; justify-content: center;\n  font-weight: 800;\n  background: var(--bg);\n  border: 1px solid var(--card-border);\n}\n\n/* ---------- Quiz ---------- */\n.option-btn {\n  display: block;\n  width: 100%;\n  text-align: right;\n  padding: 12px 16px;\n  margin-bottom: 8px;\n  border-radius: 12px;\n  border: 1px solid var(--card-border);\n  background: var(--bg);\n  color: var(--text);\n  cursor: pointer;\n  font-family: inherit;\n  font-size: 0.92rem;\n}\n\n.option-btn.selected { border-color: var(--primary); background: rgba(124,58,237,0.1); }\n.option-btn.correct { border-color: var(--success); background: rgba(22,163,74,0.12); }\n.option-btn.wrong { border-color: #ef4444; background: rgba(239,68,68,0.12); }\n\nfooter {\n  text-align: center;\n  padding: 24px;\n  color: var(--text-muted);\n  font-size: 0.85rem;\n}\n\n.badge-note {\n  font-size: 0.8rem;\n  color: var(--text-muted);\n  background: rgba(124,58,237,0.08);\n  border-radius: 10px;\n  padding: 8px 12px;\n  margin-top: 10px;\n}\n\n.alert {\n  padding: 12px 16px;\n  border-radius: 12px;\n  margin: 12px 0;\n  font-size: 0.9rem;\n}\n.alert.success { background: rgba(22,163,74,0.12); color: var(--success); }\n.alert.error { background: rgba(239,68,68,0.12); color: #ef4444; }\n\n/* ---------- Logo در نوار بالا ---------- */\n.brand-logo {\n  height: 40px;\n  width: 40px;\n  object-fit: cover;\n  border-radius: 10px;\n}\n\n/* ---------- 3D Background ---------- */\n#bg3d-canvas {\n  position: fixed;\n  inset: 0;\n  width: 100%;\n  height: 100%;\n  z-index: -1;\n  pointer-events: none;\n  opacity: 0.55;\n}\n\n[data-theme=\"dark\"] #bg3d-canvas { opacity: 0.75; }\n\n.hero {\n  position: relative;\n  overflow: hidden;\n}\n\n.hero::before {\n  content: \"\";\n  position: absolute;\n  inset: 0;\n  background-image: url('/logo.jpg');\n  background-repeat: no-repeat;\n  background-position: center;\n  background-size: 260px;\n  opacity: 0.05;\n  filter: blur(1px);\n  pointer-events: none;\n  z-index: 0;\n}\n\n.hero > * { position: relative; z-index: 1; }\n\n.brand-logo-watermark {\n  width: 120px;\n  height: 120px;\n  border-radius: 50%;\n  object-fit: cover;\n  box-shadow: 0 0 40px rgba(124, 58, 237, 0.45);\n  margin-bottom: 14px;\n  animation: floatLogo 4s ease-in-out infinite;\n}\n\n@keyframes floatLogo {\n  0%, 100% { transform: translateY(0); }\n  50% { transform: translateY(-10px); }\n}\n\nfooter {\n  position: relative;\n}\n\nfooter .footer-logo {\n  width: 34px;\n  height: 34px;\n  border-radius: 50%;\n  vertical-align: middle;\n  margin-left: 8px;\n  object-fit: cover;\n}\n"

THEME_JS = "(function () {\n  const saved = localStorage.getItem(\"noortika-theme\") || \"light\";\n  document.documentElement.setAttribute(\"data-theme\", saved);\n\n  window.addEventListener(\"DOMContentLoaded\", () => {\n    const btn = document.getElementById(\"theme-toggle-btn\");\n    updateBtnLabel(btn, saved);\n    if (btn) {\n      btn.addEventListener(\"click\", () => {\n        const current = document.documentElement.getAttribute(\"data-theme\");\n        const next = current === \"dark\" ? \"light\" : \"dark\";\n        document.documentElement.setAttribute(\"data-theme\", next);\n        localStorage.setItem(\"noortika-theme\", next);\n        updateBtnLabel(btn, next);\n      });\n    }\n  });\n\n  function updateBtnLabel(btn, theme) {\n    if (!btn) return;\n    btn.textContent = theme === \"dark\" ? \"☀️ حالت روز\" : \"🌙 حالت شب\";\n  }\n})();\n"

MAIN_JS = "const API_BASE = \"\";\n\nfunction getUserId() {\n  return localStorage.getItem(\"noortika-user-id\");\n}\n\nfunction setUserId(id) {\n  localStorage.setItem(\"noortika-user-id\", id);\n}\n\nfunction requireUser() {\n  const id = getUserId();\n  if (!id) {\n    window.location.href = \"/\";\n  }\n  return id;\n}\n\nasync function apiPost(path, body) {\n  const res = await fetch(API_BASE + path, {\n    method: \"POST\",\n    headers: { \"Content-Type\": \"application/json\" },\n    body: JSON.stringify(body),\n  });\n  if (!res.ok) {\n    const err = await res.json().catch(() => ({ detail: \"خطای ناشناخته\" }));\n    throw new Error(err.detail || \"خطا در ارتباط با سرور\");\n  }\n  return res.json();\n}\n\nasync function apiGet(path) {\n  const res = await fetch(API_BASE + path);\n  if (!res.ok) {\n    const err = await res.json().catch(() => ({ detail: \"خطای ناشناخته\" }));\n    throw new Error(err.detail || \"خطا در ارتباط با سرور\");\n  }\n  return res.json();\n}\n\ndocument.addEventListener(\"DOMContentLoaded\", () => {\n  const path = window.location.pathname;\n  document.querySelectorAll(\".nav-links a\").forEach((a) => {\n    if (a.getAttribute(\"href\") === path) a.classList.add(\"active\");\n  });\n});\n"

PLAN_JS = "let customLessons = [];\nlet lastChatPlan = null;\n\ndocument.addEventListener(\"DOMContentLoaded\", async () => {\n  const userId = requireUser();\n  if (!userId) return;\n\n  try {\n    const res = await apiGet(`/api/plans/latest/${userId}`);\n    if (res.plan && !res.plan.schedule?.[0]?.date) {\n      renderPlan(res.plan);\n    }\n  } catch (e) {\n    /* بدون برنامه قبلی، مشکلی نیست */\n  }\n\n  document.getElementById(\"add-lesson-btn\").addEventListener(\"click\", () => {\n    const name = document.getElementById(\"custom_lesson_name\").value.trim();\n    const topicsRaw = document.getElementById(\"custom_lesson_topics\").value.trim();\n    if (!name) return;\n    const topics = topicsRaw ? topicsRaw.split(\",\").map((t) => t.trim()).filter(Boolean) : [];\n    customLessons.push({ name, topics });\n    document.getElementById(\"custom_lesson_name\").value = \"\";\n    document.getElementById(\"custom_lesson_topics\").value = \"\";\n    renderCustomLessons();\n  });\n\n  document.getElementById(\"generate-btn\").addEventListener(\"click\", async () => {\n    const alertBox = document.getElementById(\"alert-box\");\n    alertBox.innerHTML = `<div class=\"alert success\">در حال ساخت برنامه توسط هوش مصنوعی نورتیکا...</div>`;\n    try {\n      const payload = {\n        user_id: parseInt(userId),\n        plan_type: \"week\",\n        custom_lessons: customLessons,\n      };\n      const data = await apiPost(\"/api/plans/generate\", payload);\n      alertBox.innerHTML = `<div class=\"alert success\">برنامه شما با موفقیت ساخته شد!</div>`;\n      renderPlan(data.plan);\n    } catch (err) {\n      alertBox.innerHTML = `<div class=\"alert error\">${err.message}</div>`;\n    }\n  });\n\n  document.getElementById(\"chat-send-btn\").addEventListener(\"click\", sendChatPlanRequest);\n\n  document.getElementById(\"log-btn\").addEventListener(\"click\", async () => {\n    const hours = parseFloat(document.getElementById(\"log_hours\").value);\n    if (!hours || hours <= 0) return;\n    try {\n      await apiPost(\"/api/study/log\", {\n        user_id: parseInt(userId),\n        hours,\n        subject: document.getElementById(\"log_subject\").value,\n      });\n      const msg = document.getElementById(\"log-msg\");\n      msg.style.display = \"inline-block\";\n      msg.textContent = \"✅ ساعت مطالعه با موفقیت ثبت شد.\";\n      document.getElementById(\"log_hours\").value = \"\";\n      document.getElementById(\"log_subject\").value = \"\";\n    } catch (err) {\n      alert(err.message);\n    }\n  });\n\n  document.getElementById(\"download-pdf-btn\").addEventListener(\"click\", downloadPlanPdf);\n});\n\nfunction renderCustomLessons() {\n  const container = document.getElementById(\"custom-lessons-list\");\n  container.innerHTML = customLessons\n    .map((l, i) => `<span class=\"day-tag\" style=\"display:inline-block;margin:4px;\">${l.name} ✕</span>`)\n    .join(\"\");\n  container.querySelectorAll(\"span\").forEach((el, i) => {\n    el.style.cursor = \"pointer\";\n    el.addEventListener(\"click\", () => {\n      customLessons.splice(i, 1);\n      renderCustomLessons();\n    });\n  });\n}\n\nasync function sendChatPlanRequest() {\n  const userId = getUserId();\n  const message = document.getElementById(\"chat_message\").value.trim();\n  const alertBox = document.getElementById(\"chat-alert-box\");\n  if (!message) {\n    alertBox.innerHTML = `<div class=\"alert error\">لطفاً پیامت را بنویس.</div>`;\n    return;\n  }\n\n  const days = Array.from(document.querySelectorAll(\".weekday-cb:checked\")).map((cb) => cb.value);\n  const startDate = document.getElementById(\"plan_start_date\").value;\n  const endDate = document.getElementById(\"plan_end_date\").value;\n\n  appendChatBubble(message, \"user\");\n  document.getElementById(\"chat_message\").value = \"\";\n  alertBox.innerHTML = `<div class=\"alert success\">هوش مصنوعی نورتیکا در حال ساخت برنامه است...</div>`;\n\n  try {\n    const data = await apiPost(\"/api/chat-planner/generate\", {\n      user_id: parseInt(userId),\n      message,\n      days_of_week: days,\n      start_date: startDate,\n      end_date: endDate,\n    });\n    alertBox.innerHTML = \"\";\n    lastChatPlan = data.plan;\n    appendChatBubble(data.plan.analysis, \"ai\");\n    renderSubjectChart(data.plan.subject_distribution);\n    renderGrowthTable(data.plan.growth_table);\n    renderDatedSchedule(data.plan);\n    document.getElementById(\"pdf-card\").style.display = \"block\";\n    document.getElementById(\"schedule-container\").scrollIntoView({ behavior: \"smooth\" });\n  } catch (err) {\n    alertBox.innerHTML = `<div class=\"alert error\">${err.message}</div>`;\n  }\n}\n\nfunction appendChatBubble(text, who) {\n  const history = document.getElementById(\"chat-history\");\n  const bubble = document.createElement(\"div\");\n  bubble.style.margin = \"8px 0\";\n  bubble.style.padding = \"10px 14px\";\n  bubble.style.borderRadius = \"14px\";\n  bubble.style.maxWidth = \"90%\";\n  bubble.style.fontSize = \"0.9rem\";\n  bubble.style.lineHeight = \"1.7\";\n  if (who === \"user\") {\n    bubble.style.background = \"linear-gradient(90deg, var(--primary), var(--primary-2))\";\n    bubble.style.color = \"#fff\";\n    bubble.style.marginRight = \"auto\";\n    bubble.style.marginLeft = \"0\";\n  } else {\n    bubble.style.background = \"var(--bg)\";\n    bubble.style.border = \"1px solid var(--card-border)\";\n    bubble.style.marginLeft = \"auto\";\n    bubble.style.marginRight = \"0\";\n  }\n  bubble.textContent = text;\n  history.appendChild(bubble);\n}\n\nlet subjectChartInstance = null;\nfunction renderSubjectChart(distribution) {\n  const chartCard = document.getElementById(\"chart-card\");\n  if (!distribution || distribution.length === 0) {\n    chartCard.style.display = \"none\";\n    return;\n  }\n  chartCard.style.display = \"block\";\n  const ctx = document.getElementById(\"subject-pie-chart\").getContext(\"2d\");\n  const colors = [\"#7c3aed\", \"#ec4899\", \"#f59e0b\", \"#16a34a\", \"#0ea5e9\", \"#f472b6\", \"#a78bfa\"];\n  if (subjectChartInstance) subjectChartInstance.destroy();\n  subjectChartInstance = new Chart(ctx, {\n    type: \"pie\",\n    data: {\n      labels: distribution.map((d) => d.subject),\n      datasets: [{\n        data: distribution.map((d) => d.percent),\n        backgroundColor: distribution.map((_, i) => colors[i % colors.length]),\n      }],\n    },\n    options: { plugins: { legend: { position: \"bottom\" } } },\n  });\n}\n\nfunction renderGrowthTable(growth) {\n  const card = document.getElementById(\"growth-card\");\n  const container = document.getElementById(\"growth-table-container\");\n  if (!growth || growth.length === 0) {\n    card.style.display = \"none\";\n    return;\n  }\n  card.style.display = \"block\";\n  const rows = growth\n    .map(\n      (g) => `\n    <div class=\"item-row\">\n      <span class=\"subject-name\">هفته ${g.week} — ${g.note || \"\"}</span>\n      <span class=\"minutes\">${g.expected_mastery_percent}٪ تسلط</span>\n    </div>`\n    )\n    .join(\"\");\n  container.innerHTML = rows;\n}\n\nfunction renderDatedSchedule(plan) {\n  const container = document.getElementById(\"schedule-container\");\n  const header = `\n    <div class=\"card\">\n      <h3>برنامه ${plan.start_date} تا ${plan.end_date}</h3>\n      <p style=\"color:var(--text-muted);font-size:0.9rem;\">\n        پایه ${plan.grade} · رشته ${plan.field} · دروس: ${plan.focus_subjects.join(\"، \")}\n      </p>\n    </div>\n  `;\n\n  const days = plan.schedule\n    .map((day) => {\n      const items = day.items\n        .map(\n          (it) => `\n        <div class=\"item-row\">\n          <span class=\"subject-name\">${it.subject} — ${it.focus}</span>\n          <span class=\"minutes\">${it.minutes} دقیقه</span>\n        </div>`\n        )\n        .join(\"\");\n      return `\n        <div class=\"day-card\">\n          <div class=\"day-title\">\n            <span>${day.date} (${day.day_name})</span>\n            <span class=\"day-tag\">${day.type}</span>\n          </div>\n          ${items}\n        </div>`;\n    })\n    .join(\"\");\n\n  container.innerHTML = header + `<div class=\"card\">${days}</div>`;\n}\n\nasync function downloadPlanPdf() {\n  if (!lastChatPlan) return;\n  try {\n    const res = await fetch(\"/api/chat-planner/pdf\", {\n      method: \"POST\",\n      headers: { \"Content-Type\": \"application/json\" },\n      body: JSON.stringify({ plan: lastChatPlan }),\n    });\n    if (!res.ok) throw new Error(\"خطا در ساخت PDF\");\n    const blob = await res.blob();\n    const url = window.URL.createObjectURL(blob);\n    const a = document.createElement(\"a\");\n    a.href = url;\n    a.download = \"noortika-plan.pdf\";\n    document.body.appendChild(a);\n    a.click();\n    a.remove();\n    window.URL.revokeObjectURL(url);\n  } catch (err) {\n    alert(err.message);\n  }\n}\n\nfunction renderPlan(plan) {\n  if (plan.ai_advice) {\n    document.getElementById(\"advice-card\").style.display = \"block\";\n    document.getElementById(\"advice-text\").textContent = plan.ai_advice;\n  }\n\n  const container = document.getElementById(\"schedule-container\");\n  const header = `\n    <div class=\"card\">\n      <h3>برنامه ${planTypeLabel(plan.plan_type)} — سطح جزئیات: ${plan.detail_level}</h3>\n      <p style=\"color:var(--text-muted);font-size:0.9rem;\">\n        پایه ${plan.grade} · رشته ${plan.field} ${plan.target_major ? \"· هدف: \" + plan.target_major : \"\"}\n      </p>\n    </div>\n  `;\n\n  const days = plan.schedule\n    .map((day) => {\n      const items = day.items\n        .map(\n          (it) => `\n        <div class=\"item-row\">\n          <span class=\"subject-name\">${it.subject} — ${it.focus}</span>\n          <span class=\"minutes\">${it.minutes} دقیقه</span>\n        </div>`\n        )\n        .join(\"\");\n      return `\n        <div class=\"day-card\">\n          <div class=\"day-title\">\n            <span>روز ${day.day}</span>\n            <span class=\"day-tag\">${day.type}</span>\n          </div>\n          ${items}\n        </div>`;\n    })\n    .join(\"\");\n\n  container.innerHTML = header + `<div class=\"card\">${days}</div>`;\n}\n\nfunction planTypeLabel(type) {\n  const map = { week: \"هفتگی\", month: \"ماهانه\", six_month: \"شش‌ماهه\", year: \"یک‌ساله\" };\n  return map[type] || type;\n}\n"

EXAM_JS = "let userField = \"\";\nlet currentQuiz = null;\nlet userAnswers = [];\n\ndocument.addEventListener(\"DOMContentLoaded\", async () => {\n  const userId = requireUser();\n  if (!userId) return;\n\n  try {\n    const user = await apiGet(`/api/users/${userId}`);\n    userField = user.field;\n    document.getElementById(\"exam_grade\").value = user.grade;\n    await loadSubjects();\n  } catch (e) {\n    console.error(e);\n  }\n\n  document.getElementById(\"exam_grade\").addEventListener(\"change\", loadSubjects);\n\n  document.getElementById(\"start-exam-btn\").addEventListener(\"click\", startExam);\n});\n\nasync function loadSubjects() {\n  const grade = document.getElementById(\"exam_grade\").value;\n  try {\n    const res = await apiGet(`/api/plans/subjects?grade=${encodeURIComponent(grade)}&field=${encodeURIComponent(userField)}`);\n    const select = document.getElementById(\"exam_subject\");\n    select.innerHTML = res.subjects.map((s) => `<option value=\"${s.name}\">${s.name}</option>`).join(\"\");\n  } catch (e) {\n    console.error(e);\n  }\n}\n\nasync function startExam() {\n  const alertBox = document.getElementById(\"alert-box\");\n  alertBox.innerHTML = `<div class=\"alert success\">در حال طراحی سوالات توسط هوش مصنوعی...</div>`;\n  document.getElementById(\"result-card\").style.display = \"none\";\n  document.getElementById(\"wrong-analysis-container\").innerHTML = \"\";\n\n  const payload = {\n    user_id: parseInt(getUserId()),\n    subject: document.getElementById(\"exam_subject\").value,\n    grade: document.getElementById(\"exam_grade\").value,\n    question_count: parseInt(document.getElementById(\"exam_count\").value),\n    difficulty: document.getElementById(\"exam_difficulty\").value,\n    question_type: document.getElementById(\"exam_type\").value,\n  };\n\n  try {\n    const data = await apiPost(\"/api/exams/generate\", payload);\n    currentQuiz = data.quiz;\n    userAnswers = new Array(currentQuiz.questions.length).fill(currentQuiz.question_type === \"تشریحی\" ? \"\" : null);\n    alertBox.innerHTML = \"\";\n    renderQuiz();\n  } catch (err) {\n    alertBox.innerHTML = `<div class=\"alert error\">${err.message}</div>`;\n  }\n}\n\nfunction renderQuiz() {\n  const container = document.getElementById(\"quiz-container\");\n\n  if (currentQuiz.question_type === \"تشریحی\") {\n    const html = currentQuiz.questions\n      .map(\n        (q, qi) => `\n    <div class=\"card\">\n      <h4>سوال ${qi + 1} از ${currentQuiz.questions.length} (تشریحی)</h4>\n      <p>${q.question}</p>\n      <textarea data-qi=\"${qi}\" class=\"essay-answer\" rows=\"4\" style=\"width:100%;padding:12px;border-radius:12px;border:1px solid var(--card-border);background:var(--bg);color:var(--text);font-family:inherit;\" placeholder=\"پاسخ خود را اینجا تایپ کنید...\"></textarea>\n    </div>`\n      )\n      .join(\"\");\n\n    container.innerHTML =\n      html + `<button id=\"submit-exam-btn\" class=\"btn block\" style=\"margin:20px 0;\">پایان آزمون و مشاهده تحلیل</button>`;\n\n    container.querySelectorAll(\".essay-answer\").forEach((ta) => {\n      ta.addEventListener(\"input\", () => {\n        userAnswers[parseInt(ta.dataset.qi)] = ta.value;\n      });\n    });\n\n    document.getElementById(\"submit-exam-btn\").addEventListener(\"click\", submitEssayExam);\n    return;\n  }\n\n  const html = currentQuiz.questions\n    .map(\n      (q, qi) => `\n    <div class=\"card\">\n      <h4>سوال ${qi + 1} از ${currentQuiz.questions.length}</h4>\n      <p>${q.question}</p>\n      <div class=\"options\" data-qi=\"${qi}\">\n        ${q.options\n          .map(\n            (opt, oi) => `<button type=\"button\" class=\"option-btn\" data-qi=\"${qi}\" data-oi=\"${oi}\">${opt}</button>`\n          )\n          .join(\"\")}\n      </div>\n    </div>`\n    )\n    .join(\"\");\n\n  container.innerHTML =\n    html + `<button id=\"submit-exam-btn\" class=\"btn block\" style=\"margin:20px 0;\">پایان آزمون و مشاهده نتیجه</button>`;\n\n  container.querySelectorAll(\".option-btn\").forEach((btn) => {\n    btn.addEventListener(\"click\", () => {\n      const qi = parseInt(btn.dataset.qi);\n      const oi = parseInt(btn.dataset.oi);\n      userAnswers[qi] = oi;\n      document\n        .querySelectorAll(`.option-btn[data-qi=\"${qi}\"]`)\n        .forEach((b) => b.classList.remove(\"selected\"));\n      btn.classList.add(\"selected\");\n    });\n  });\n\n  document.getElementById(\"submit-exam-btn\").addEventListener(\"click\", submitExam);\n}\n\nasync function submitExam() {\n  const correctAnswers = currentQuiz.questions.map((q) => q.correct_index);\n\n  document.querySelectorAll(\".options\").forEach((optDiv) => {\n    const qi = parseInt(optDiv.dataset.qi);\n    const correctIdx = correctAnswers[qi];\n    optDiv.querySelectorAll(\".option-btn\").forEach((btn) => {\n      const oi = parseInt(btn.dataset.oi);\n      if (oi === correctIdx) btn.classList.add(\"correct\");\n      else if (oi === userAnswers[qi] && oi !== correctIdx) btn.classList.add(\"wrong\");\n      btn.disabled = true;\n    });\n  });\n\n  try {\n    const data = await apiPost(\"/api/exams/submit\", {\n      user_id: parseInt(getUserId()),\n      subject: currentQuiz.subject,\n      lesson: currentQuiz.lesson,\n      grade: currentQuiz.grade,\n      difficulty: currentQuiz.difficulty,\n      answers: userAnswers.map((a) => (a === null ? -1 : a)),\n      correct_answers: correctAnswers,\n      questions: currentQuiz.questions,\n    });\n\n    const resultCard = document.getElementById(\"result-card\");\n    resultCard.style.display = \"block\";\n    document.getElementById(\"result-text\").innerHTML =\n      `تعداد پاسخ صحیح: <b>${data.correct_count}</b> از ${data.total} — درصد: <b>${data.score_percent}%</b><br/>` +\n      `این نتیجه در رتبه‌بندی نورتیکا نیز لحاظ می‌شود. 🎉`;\n\n    renderWrongAnalysis(data.wrong_analysis);\n    resultCard.scrollIntoView({ behavior: \"smooth\" });\n  } catch (err) {\n    alert(err.message);\n  }\n}\n\nasync function submitEssayExam() {\n  const answers = currentQuiz.questions.map((q, qi) => ({\n    question: q.question,\n    student_answer: userAnswers[qi] || \"\",\n    model_answer: q.model_answer || \"\",\n  }));\n\n  try {\n    const data = await apiPost(\"/api/exams/essay/submit\", {\n      user_id: parseInt(getUserId()),\n      subject: currentQuiz.subject,\n      grade: currentQuiz.grade,\n      difficulty: currentQuiz.difficulty,\n      answers,\n    });\n\n    const resultCard = document.getElementById(\"result-card\");\n    resultCard.style.display = \"block\";\n    document.getElementById(\"result-text\").innerHTML =\n      `میانگین درصد پاسخ‌های تشریحی شما: <b>${data.average_score_percent}%</b><br/>` +\n      `تحلیل کامل هر پاسخ در پایین آمده است. 📝`;\n\n    renderEssayAnalysis(data.analysis);\n    resultCard.scrollIntoView({ behavior: \"smooth\" });\n  } catch (err) {\n    alert(err.message);\n  }\n}\n\nfunction renderWrongAnalysis(items) {\n  const container = document.getElementById(\"wrong-analysis-container\");\n  if (!items || items.length === 0) {\n    container.innerHTML = `<p style=\"color:var(--success);font-weight:700;margin-top:12px;\">🎉 همه پاسخ‌های شما درست بود!</p>`;\n    return;\n  }\n  const html = items\n    .map(\n      (it, i) => `\n    <div class=\"card\" style=\"margin-top:12px;border-color:#ef4444;\">\n      <h4>تحلیل سوال غلط ${i + 1}</h4>\n      <p><b>سوال:</b> ${it.question}</p>\n      <p style=\"color:#ef4444;\"><b>پاسخ شما:</b> ${it.your_answer}</p>\n      <p style=\"color:var(--success);\"><b>پاسخ صحیح:</b> ${it.correct_answer}</p>\n      <p><b>توضیح هوش مصنوعی:</b> ${it.explanation}</p>\n    </div>`\n    )\n    .join(\"\");\n  container.innerHTML = `<h3 style=\"margin-top:20px;\">تحلیل سوالات غلط توسط هوش مصنوعی</h3>` + html;\n}\n\nfunction renderEssayAnalysis(items) {\n  const container = document.getElementById(\"wrong-analysis-container\");\n  if (!items || items.length === 0) {\n    container.innerHTML = \"\";\n    return;\n  }\n  const html = items\n    .map(\n      (it, i) => `\n    <div class=\"card\" style=\"margin-top:12px;\">\n      <h4>سوال ${i + 1} — امتیاز: ${it.score_percent}%</h4>\n      <p><b>سوال:</b> ${it.question}</p>\n      <p><b>پاسخ شما:</b> ${it.student_answer}</p>\n      <p style=\"color:var(--success);\"><b>پاسخ کامل و صحیح:</b> ${it.correct_answer}</p>\n      <p><b>بازخورد:</b> ${it.explanation}</p>\n    </div>`\n    )\n    .join(\"\");\n  container.innerHTML = `<h3 style=\"margin-top:20px;\">تحلیل پاسخ‌های تشریحی</h3>` + html;\n}\n"

BG3D_JS = "(function () {\n  function initNoortikaBg3D() {\n    const canvas = document.getElementById(\"bg3d-canvas\");\n    if (!canvas || typeof THREE === \"undefined\") return;\n\n    const scene = new THREE.Scene();\n    const camera = new THREE.PerspectiveCamera(\n      60,\n      window.innerWidth / window.innerHeight,\n      0.1,\n      1000\n    );\n    camera.position.z = 42;\n\n    const renderer = new THREE.WebGLRenderer({\n      canvas: canvas,\n      alpha: true,\n      antialias: true,\n    });\n    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));\n    renderer.setSize(window.innerWidth, window.innerHeight);\n    renderer.setClearColor(0x000000, 0);\n\n    // ---------- ابرِ ذرات درخشان (Particles) ----------\n    const particleCount = window.innerWidth < 640 ? 120 : 260;\n    const positions = new Float32Array(particleCount * 3);\n    const colors = new Float32Array(particleCount * 3);\n    const brandColors = [\n      new THREE.Color(0x7c3aed),\n      new THREE.Color(0xec4899),\n      new THREE.Color(0xf59e0b),\n      new THREE.Color(0xa78bfa),\n    ];\n\n    for (let i = 0; i < particleCount; i++) {\n      positions[i * 3] = (Math.random() - 0.5) * 90;\n      positions[i * 3 + 1] = (Math.random() - 0.5) * 60;\n      positions[i * 3 + 2] = (Math.random() - 0.5) * 60;\n      const c = brandColors[Math.floor(Math.random() * brandColors.length)];\n      colors[i * 3] = c.r;\n      colors[i * 3 + 1] = c.g;\n      colors[i * 3 + 2] = c.b;\n    }\n\n    const particleGeometry = new THREE.BufferGeometry();\n    particleGeometry.setAttribute(\"position\", new THREE.BufferAttribute(positions, 3));\n    particleGeometry.setAttribute(\"color\", new THREE.BufferAttribute(colors, 3));\n\n    const particleMaterial = new THREE.PointsMaterial({\n      size: 0.6,\n      vertexColors: true,\n      transparent: true,\n      opacity: 0.85,\n      blending: THREE.AdditiveBlending,\n      depthWrite: false,\n    });\n\n    const particles = new THREE.Points(particleGeometry, particleMaterial);\n    scene.add(particles);\n\n    // ---------- چندضلعی‌های شناور (Wireframe Icosahedrons) ----------\n    const shapes = [];\n    const shapeColors = [0x7c3aed, 0xec4899, 0xf59e0b];\n    const shapeCount = window.innerWidth < 640 ? 2 : 4;\n\n    for (let i = 0; i < shapeCount; i++) {\n      const geo = new THREE.IcosahedronGeometry(3 + Math.random() * 2.5, 0);\n      const mat = new THREE.MeshBasicMaterial({\n        color: shapeColors[i % shapeColors.length],\n        wireframe: true,\n        transparent: true,\n        opacity: 0.5,\n      });\n      const mesh = new THREE.Mesh(geo, mat);\n      mesh.position.set(\n        (Math.random() - 0.5) * 60,\n        (Math.random() - 0.5) * 34,\n        (Math.random() - 0.5) * 30 - 10\n      );\n      mesh.userData = {\n        speed: 0.002 + Math.random() * 0.004,\n        floatSpeed: 0.4 + Math.random() * 0.6,\n        floatOffset: Math.random() * Math.PI * 2,\n        baseY: mesh.position.y,\n      };\n      scene.add(mesh);\n      shapes.push(mesh);\n    }\n\n    // ---------- لوگوی شناور نورتیکا در پس‌زمینه ----------\n    const logoTexture = new THREE.TextureLoader().load(\"/logo.jpg\");\n    const logoGeo = new THREE.CircleGeometry(6, 48);\n    const logoMat = new THREE.MeshBasicMaterial({\n      map: logoTexture,\n      transparent: true,\n      opacity: 0.18,\n      depthWrite: false,\n    });\n    const logoMesh = new THREE.Mesh(logoGeo, logoMat);\n    logoMesh.position.set(16, 8, -20);\n    scene.add(logoMesh);\n\n    const logoMesh2 = new THREE.Mesh(logoGeo.clone(), logoMat.clone());\n    logoMesh2.scale.set(0.6, 0.6, 0.6);\n    logoMesh2.position.set(-18, -10, -25);\n    scene.add(logoMesh2);\n\n    window.addEventListener(\"resize\", () => {\n      camera.aspect = window.innerWidth / window.innerHeight;\n      camera.updateProjectionMatrix();\n      renderer.setSize(window.innerWidth, window.innerHeight);\n    });\n\n    const clock = new THREE.Clock();\n\n    function animate() {\n      requestAnimationFrame(animate);\n      const t = clock.getElapsedTime();\n\n      particles.rotation.y = t * 0.02;\n      particles.rotation.x = t * 0.01;\n\n      shapes.forEach((mesh) => {\n        mesh.rotation.x += mesh.userData.speed;\n        mesh.rotation.y += mesh.userData.speed * 1.3;\n        mesh.position.y =\n          mesh.userData.baseY + Math.sin(t * mesh.userData.floatSpeed + mesh.userData.floatOffset) * 1.5;\n      });\n\n      logoMesh.rotation.z = t * 0.05;\n      logoMesh2.rotation.z = -t * 0.04;\n      logoMesh.position.y = 8 + Math.sin(t * 0.3) * 2;\n      logoMesh2.position.y = -10 + Math.sin(t * 0.25 + 2) * 2;\n\n      renderer.render(scene, camera);\n    }\n\n    animate();\n  }\n\n  if (document.readyState === \"loading\") {\n    document.addEventListener(\"DOMContentLoaded\", initNoortikaBg3D);\n  } else {\n    initNoortikaBg3D();\n  }\n})();\n"
